import re

def detect_tool_chain_errors(messages):
    tool_calls = []
    for msg in messages:
        if msg.get('type') == 'tool_use':
            tool_calls.append(msg['content'])

    for i, call in enumerate(tool_calls):
        if 'result' in call and call['result'] is None:
            for later_call in tool_calls[i+1:]:
                if re.search(re.escape(call['name']), later_call['input'].get('json', '')):
                    return {
                        'error': 'Cascading null propagation',
                        'tool': call['name'],
                        'location': i
                    }
    return None

from anthropic.types import ToolUseBlock

def detect_parallel_conflicts(response):
    parallel_tools = [block for block in response.content if isinstance(block, ToolUseBlock)]
    results = {}

    for tool in parallel_tools:
        name = tool.name
        result = tool.input.get('result')
        if isinstance(result, (int, float)):
            if name in results:
                if abs(results[name] - result) > 0.01:
                    return f'Conflict: {name} {results[name]} vs {result}'
            results[name] = result
    return None

import re

def detect_reasoning_divergence(message):
    text_content = ''
    tool_content = []

    for content in message.content:
        if content.type == 'text':
            text_content += content.text
        elif content.type == 'tool_use':
            tool_content.append(content.name)

    budget_intent = bool(re.search(r'budget|cheap|affordable|under\s*\$?\d+', text_content, re.I))
    premium_tools = any(tool in ['premium_flight', 'luxury_hotel'] for tool in tool_content)

    if budget_intent and premium_tools:
        return 'Reasoning mentions budget but calls premium tools'
    return None

