from anthropic import Anthropic
client = Anthropic()

def safe_tool_chain(messages, tools):
    response = client.messages.create(
        model="claude-3-5-sonnet-20240620",
        max_tokens=1024,
        tools=tools,
        messages=messages
    )

    # Check for failed tools and retry
    for content in response.content:
        if content.type == 'tool_use' and content.input.get('result') is None:
            # Retry with corrected params
            retry_msg = {
                'role': 'user',
                'content': [{
                    'type': 'tool_result',
                    'tool_use_id': content.id,
                    'content': 'Using default location: NYC',
                    'is_error': False
                }]
            }
            response = client.messages.create(
                model="claude-3-5-sonnet-20240620",
                max_tokens=1024,
                tools=tools,
                messages=messages + [retry_msg]
            )
    return response

import re

def intent_aligned_dispatch(message):
    intent = extract_intent(message.content[0].text)
    available_tools = {
        'budget': ['economy_flight', 'budget_hotel'],
        'premium': ['premium_flight', 'luxury_hotel']
    }

    allowed_tools = available_tools.get(intent, list(available_tools.keys()))

    # Filter tool calls
    filtered_content = []
    for content in message.content:
        if content.type != 'tool_use' or content.name in allowed_tools:
            filtered_content.append(content)

    return filtered_content

def extract_intent(text):
    if re.search(r'budget|cheap|affordable', text, re.I):
        return 'budget'
    return 'premium'
